import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

type StepperContextValue = {
  activeStep: string
  orientation: "horizontal" | "vertical"
  onStepChange: (value: string) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextValue = {
  value: string
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

type StepperProps = {
  defaultValue?: string
  value?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  defaultValue,
  value: controlledValue,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [uncontrolledValue, setUncontrolledValue] = React.useState(
    defaultValue ?? ""
  )

  const activeStep = controlledValue ?? uncontrolledValue

  const onStepChange = React.useCallback(
    (newValue: string) => {
      if (controlledValue === undefined) {
        setUncontrolledValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [controlledValue, onValueChange]
  )

  return (
    <StepperContext.Provider value={{ activeStep, orientation, onStepChange }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex gap-4",
          orientation === "horizontal" ? "flex-col" : "flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

type StepperItemProps = {
  value: string
  step: number
  disabled?: boolean
  completed?: boolean
}

function StepperItem({
  value,
  step,
  disabled = false,
  completed,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === value
  const isCompleted = completed ?? false

  return (
    <StepperItemContext.Provider
      value={{ value, step, isActive, isCompleted, isDisabled: disabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={
          isActive ? "active" : isCompleted ? "completed" : "inactive"
        }
        aria-current={isActive ? "step" : undefined}
        className={cn(
          "cn-stepper-item group/stepper-item relative flex items-center gap-2",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { value, step, isActive, isCompleted, isDisabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={
        isActive ? "active" : isCompleted ? "completed" : "inactive"
      }
      type="button"
      disabled={isDisabled}
      className={cn(
        "cn-stepper-trigger flex items-center gap-3 rounded-md outline-none transition-colors focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onStepChange(value)}
      {...props}
    >
      <span
        data-slot="stepper-indicator"
        data-state={
          isActive ? "active" : isCompleted ? "completed" : "inactive"
        }
        className={cn(
          "cn-stepper-indicator flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors",
          isActive && "border-primary bg-primary text-primary-foreground",
          isCompleted && "border-primary bg-primary text-primary-foreground",
          !isActive &&
            !isCompleted &&
            "border-muted-foreground/25 text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <IconPlaceholder
            lucide="CheckIcon"
            tabler="IconCheck"
            hugeicons="Tick02Icon"
            phosphor="CheckIcon"
            remixicon="RiCheckLine"
            className="size-4"
          />
        ) : (
          step
        )}
      </span>
      {children}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      role="separator"
      className={cn(
        "cn-stepper-separator bg-muted-foreground/25 data-[state=completed]:bg-primary",
        orientation === "horizontal"
          ? "h-px w-full flex-1 self-center"
          : "ml-4 h-full min-h-8 w-px self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { value: string }) {
  const { activeStep } = useStepper()

  if (activeStep !== value) return null

