}: React.ComponentProps<"div"> & StepperItemProps) {
  const { activeStep } = useStepper()
  const isActive = activeStep === value
  const isCompleted = completed ?? false

  return (
    <StepperItemContext.Provider
      value={{ value, step, isActive, isCompleted, isDisabled: disabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={
          isActive ? "active" : isCompleted ? "completed" : "inactive"
        }
        aria-current={isActive ? "step" : undefined}
        className={cn(
          "group/stepper-item relative flex items-center gap-2",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { value, step, isActive, isCompleted, isDisabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={
        isActive ? "active" : isCompleted ? "completed" : "inactive"
      }
      type="button"
      disabled={isDisabled}
      className={cn(
        "flex items-center gap-3 rounded-md outline-none transition-colors focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onStepChange(value)}
      {...props}
    >
      <span
        data-slot="stepper-indicator"
        data-state={
          isActive ? "active" : isCompleted ? "completed" : "inactive"
        }
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors",
          isActive && "border-primary bg-primary text-primary-foreground",
          isCompleted && "border-primary bg-primary text-primary-foreground",
          !isActive &&
            !isCompleted &&
            "border-muted-foreground/25 text-muted-foreground"
        )}
      >
        {isCompleted ? <Check className="size-4" /> : step}
      </span>
      {children}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      role="separator"
      className={cn(
        "bg-muted-foreground/25 data-[state=completed]:bg-primary",
        orientation === "horizontal"
          ? "h-px w-full flex-1 self-center"
          : "ml-4 h-full min-h-8 w-px self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { value: string }) {
  const { activeStep } = useStepper()

  if (activeStep !== value) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

